// Extract video URLs from HTML content
const bodyHtml = $input.item.json.body_html || '';
const videoUrls = [];

// Regular expressions for different video sources
const patterns = [
  // YouTube iframe embeds
  /<iframe[^>]*src=["'](?:https?:)?\/\/(?:www\.)?(?:youtube\.com\/embed\/|youtu\.be\/)([^"'\s]+)["'][^>]*>/gi,
  // Vimeo iframe embeds
  /<iframe[^>]*src=["'](?:https?:)?\/\/(?:www\.)?(?:player\.)?vimeo\.com\/(?:video\/)?([^"'\s]+)["'][^>]*>/gi,
  // HTML5 video tags
  /<video[^>]*src=["']([^"']+)["'][^>]*>/gi,
  // Source tags within video elements
  /<source[^>]*src=["']([^"']+)["'][^>]*>/gi,
  // Direct video URLs in href or data attributes
  /(?:href|data-video-url|data-src)=["']([^"']*\.(?:mp4|webm|ogg|mov|avi)(?:\?[^"']*)?)["']/gi
];

// Extract URLs using each pattern
for (const pattern of patterns) {
  let match;
  while ((match = pattern.exec(bodyHtml)) !== null) {
    const url = match[1];
    if (url && !videoUrls.includes(url)) {
      // Normalize YouTube URLs
      if (url.includes('youtube.com') || url.includes('youtu.be')) {
        const videoId = url.split('/').pop().split('?')[0];
        videoUrls.push(`https://www.youtube.com/watch?v=${videoId}`);
      }
      // Normalize Vimeo URLs
      else if (url.includes('vimeo.com')) {
        const videoId = url.split('/').pop().split('?')[0];
        videoUrls.push(`https://vimeo.com/${videoId}`);
      }
      // Keep other URLs as-is
      else {
        videoUrls.push(url);
      }
    }
  }
}

return {
  json: {
    body_html: bodyHtml,
    video_urls: videoUrls,
    video_count: videoUrls.length
  }
};

// Strip HTML tags and convert to clean text
const bodyHtml = $input.item.json.body_html || '';
const videoUrls = $input.item.json.video_urls || [];

// Remove script and style tags completely
let cleanText = bodyHtml.replace(/<script[^>]*>.*?<\/script>/gis, '');
cleanText = cleanText.replace(/<style[^>]*>.*?<\/style>/gis, '');

// Convert common HTML entities
const entities = {
  '&nbsp;': ' ',
  '&amp;': '&',
  '&lt;': '<',
  '&gt;': '>',
  '&quot;': '"',
  '&#39;': "'",
  '&mdash;': '—',
  '&ndash;': '–',
  '&hellip;': '...',
  '&bull;': '•'
};

for (const [entity, char] of Object.entries(entities)) {
  cleanText = cleanText.replace(new RegExp(entity, 'g'), char);
}

// Convert block-level elements to line breaks
cleanText = cleanText.replace(/<\/?(div|p|br|h[1-6]|li|tr)[^>]*>/gi, '\n');

// Remove all remaining HTML tags
cleanText = cleanText.replace(/<[^>]+>/g, '');

// Clean up whitespace
cleanText = cleanText
  .split('\n')
  .map(line => line.trim())
  .filter(line => line.length > 0)
  .join('\n');

// Remove excessive line breaks (more than 2 consecutive)
cleanText = cleanText.replace(/\n{3,}/g, '\n\n');

return {
  json: {
    marketing_copy: cleanText.trim(),
    video_urls: videoUrls,
    original_html_length: bodyHtml.length,
    clean_text_length: cleanText.length,
    has_videos: videoUrls.length > 0
  }
};
